    int occupied;
} Entry;

typedef struct {
    Entry *table;
    int size;
    int count;
} HashTable;

int h1(int key, int m) { return key % m; }
int h2(int key, int m) { return 7 - (key % 7); }

int doubleHash(HashTable *ht, int key) {
    int i = 0, index;
    while (i < ht->size) {
        index = (h1(key, ht->size) + i * h2(key, ht->size)) % ht->size;
        if (!ht->table[index].occupied) {
            return index;
        }
        i++;
    }
    return -1; // Table full
}

